class FoodRatings {
    private Map<String, Map<String, Integer>> cuisineFoodRating;
    private Map<String, String> highestRatedFood;

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        cuisineFoodRating = new HashMap<>();
        highestRatedFood = new HashMap<>();
        for (int i = 0; i < foods.length; i++) {
            cuisineFoodRating.computeIfAbsent(cuisines[i], k -> new HashMap<>()).put(foods[i], ratings[i]);
            highestRatedFood.put(cuisines[i], foods[i]);
        }
    }

    public void changeRating(String food, int newRating) {
        for (Map.Entry<String, Map<String, Integer>> entry : cuisineFoodRating.entrySet()) {
            if (entry.getValue().containsKey(food)) {
                entry.getValue().put(food, newRating);
                String highestFood = null;
                int highestRating = 0;
                for (Map.Entry<String, Integer> foodRating : entry.getValue().entrySet()) {
                    if (foodRating.getValue() > highestRating || (foodRating.getValue() == highestRating && foodRating.getKey().compareTo(highestFood) < 0)) {
                        highestFood = foodRating.getKey();
                        highestRating = foodRating.getValue();
                    }
                }
                highestRatedFood.put(entry.getKey(), highestFood);
                break;
            }
        }
    }

    public String highestRated(String cuisine) {
        return highestRatedFood.get(cuisine);
    }
}
